(8571, 164, 'content_8_slides_6_sub', ''),
(8572, 164, '_content_8_slides_6_sub', 'field_65e65a109a31a'),
(8573, 164, 'content_8_slides_6_txt', 'En el 2010 empezó impartiendo clases usando el método de pilates contemporáneo y clásico atendiendo a todas las necesidades y edades en la casa club bosque real. En el 2020 empecé a impartir clases grupales de las técnicas Pilates Mat y Body Art.'),
(8574, 164, '_content_8_slides_6_txt', 'field_65e65a1d9a31b'),
