(8607, 164, 'content_8_slides_11_img', '112'),
(8608, 164, '_content_8_slides_11_img', 'field_65e659d69a318'),
(8609, 164, 'content_8_slides_11_ttl', 'Irasema Ledesma'),
(8610, 164, '_content_8_slides_11_ttl', 'field_65e659e99a319'),
(8611, 164, 'content_8_slides_11_sub', ''),
(8612, 164, '_content_8_slides_11_sub', 'field_65e65a109a31a'),
(8613, 164, 'content_8_slides_11_txt', 'Su experiencia incluye certificaciones internacionales en una amplia gama de disciplinas. En la actualidad, ella se desempeña como coach especializada en Pilates Reformer, Mat con accesorios y también en entrenamientos personalizados que integran movimientos funcionales con Pilates Mat y Reformer. Su enfoque siempre ha sido conectar la mente con el cuerpo de manera eficiente y dinámica.'),
