(9625, 171, 'content_8_slides_0_txt', 'Cree firmemente que el yoga es una práctica constante en la cual nunca se deja de aprender.\r\nCuenta con una certificación de 300 horas en Hatha Vinyasa y 100 horas avanzadas con Fabian Montes de Oca.'),
(9626, 171, '_content_8_slides_0_txt', 'field_65e65a1d9a31b'),
(9627, 171, 'content_8_slides_1_img', '105'),
