(9632, 171, '_content_8_slides_1_sub', 'field_65e65a109a31a'),
(9633, 171, 'content_8_slides_1_txt', 'Ana se certificó con Middle Path Movement en Sayulita, Nayarit como instructora de Hatha Yoga y Vinyasa. En sus clases, se enfoca en fortalecer el cuerpo y la mente mediante la meditación, el movimiento fluido y la respiración consciente.'),
(9634, 171, '_content_8_slides_1_txt', 'field_65e65a1d9a31b'),
(9635, 171, 'content_8_slides_2_img', '113'),
(9636, 171, '_content_8_slides_2_img', 'field_65e659d69a318'),
