(9856, 172, '_content_8_slides_0_sub', 'field_65e65a109a31a'),
(9857, 172, 'content_8_slides_0_txt', 'She firmly believes that yoga is a constant practice in which one never stops learning. They hold a 300-hour certification in Hatha Vinyasa and 100 advanced hours with Fabian Montes de Oca.'),
(9858, 172, '_content_8_slides_0_txt', 'field_65e65a1d9a31b'),
