(9864, 172, '_content_8_slides_1_sub', 'field_65e65a109a31a'),
(9865, 172, 'content_8_slides_1_txt', 'Ana got certified with Middle Path Movement in Sayulita, Nayarit, as a Hatha Yoga and Vinyasa instructor. In her classes, she focuses on strengthening the body and mind through  meditation, fluid movement and conscious breathing.'),
(9866, 172, '_content_8_slides_1_txt', 'field_65e65a1d9a31b'),
(9867, 172, 'content_8_slides_2_img', '113'),
