(3168, 123, '_content_2_items_0_sub', 'field_65e655cd9a310'),
(3169, 123, 'content_2_items_1_txt', 'Tonifica tu cuerpo a través de movimientos continuos y resistencia aplicando las posturas y respiraciones fundamentales de reformer pilates.\r\n\r\n<a href=\"https://reformstudio.com.mx/reserva\">RESERVA TU SESIÓN</a>'),
