(3903, 131, 'content_2_items_0_txt', 'Utiliza ejercicios de resistencia, estiramiento y respiración para reformar tu cuerpo y tu mente.\r\n\r\n<a href=\"https://reformstudio.com.mx/reserva\">RESERVA TU SESIÓN</a>'),
(3904, 131, '_content_2_items_0_txt', 'field_65e6565c9a311'),
(3905, 131, 'content_2_items_0_ttl', 'Sesión Classic Reformer'),
(3906, 131, '_content_2_items_0_ttl', 'field_65e655c09a30f'),
(3907, 131, 'content_2_items_0_sub', '50 minutos. todos los niveles.'),
(3908, 131, '_content_2_items_0_sub', 'field_65e655cd9a310'),
(3909, 131, 'content_2_items_1_txt', 'Tonifica tu cuerpo a través de movimientos continuos y resistencia aplicando las posturas y respiraciones fundamentales de reformer pilates.\r\n\r\n<a href=\"https://reformstudio.com.mx/reserva\">RESERVA TU SESIÓN</a>'),
(3910, 131, '_content_2_items_1_txt', 'field_65e6565c9a311'),
(3911, 131, 'content_2_items_1_ttl', 'Sesión Flow Reformer'),
(3912, 131, '_content_2_items_1_ttl', 'field_65e655c09a30f'),
(3913, 131, 'content_2_items_1_sub', '50 minutos. NIVEL INTERMEDIO.'),
(3914, 131, '_content_2_items_1_sub', 'field_65e655cd9a310'),
(3915, 131, 'content_2_items_2_txt', 'Fortalece tu cuerpo haciendo ejercicios funcionales usando peso, resistencias y diversos accesorios en el reformer.\r\n\r\n<a href=\"https://reformstudio.com.mx/reserva\">RESERVA TU SESIÓN</a>'),
(3916, 131, '_content_2_items_2_txt', 'field_65e6565c9a311'),
(3917, 131, 'content_2_items_2_ttl', 'Sesión Burn Reformer'),
(3918, 131, '_content_2_items_2_ttl', 'field_65e655c09a30f'),
