(5225, 140, 'content_2_items_0_txt', 'Utiliza ejercicios de resistencia, estiramiento y respiración para reformar tu cuerpo y tu mente.\r\n\r\n<a href=\"https://reformstudio.com.mx/reserva\">RESERVA TU SESIÓN</a>'),
(5226, 140, '_content_2_items_0_txt', 'field_65e6565c9a311'),
