(5230, 140, '_content_2_items_0_sub', 'field_65e655cd9a310'),
(5231, 140, 'content_2_items_1_txt', 'Tonifica tu cuerpo a través de movimientos continuos y resistencia aplicando las posturas y respiraciones fundamentales de reformer pilates.\r\n\r\n<a href=\"https://reformstudio.com.mx/reserva\">RESERVA TU SESIÓN</a>'),
(5232, 140, '_content_2_items_1_txt', 'field_65e6565c9a311'),
(5233, 140, 'content_2_items_1_ttl', 'Sesión Flow Reformer'),
(5234, 140, '_content_2_items_1_ttl', 'field_65e655c09a30f'),
(5235, 140, 'content_2_items_1_sub', '50 minutos. NIVEL INTERMEDIO.'),
(5236, 140, '_content_2_items_1_sub', 'field_65e655cd9a310'),
(5237, 140, 'content_2_items_2_txt', 'Fortalece tu cuerpo haciendo ejercicios funcionales usando peso, resistencias y diversos accesorios en el reformer.\r\n\r\n<a href=\"https://reformstudio.com.mx/reserva\">RESERVA TU SESIÓN</a>'),
(5238, 140, '_content_2_items_2_txt', 'field_65e6565c9a311'),
