(6471, 154, 'content_4_items_0_txt', 'Utiliza ejercicios de estiramiento y respiración usando peso corporal para reformar  INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(6831, 155, 'content_8_slides_8_sub', ''),
(6832, 155, '_content_8_slides_8_sub', 'field_65e65a109a31a'),
(6833, 155, 'content_8_slides_8_txt', 'Se certificó en Balance in Motion con Cristina Loyola en Pilates Reformer básico, intermedio y también en Pilates Mat. Camilla comenzó a dar clases privadas desde su casa junto con su hermana, Karla. Así fundando Reform Studio.'),
(6834, 155, '_content_8_slides_8_txt', 'field_65e65a1d9a31b'),
(6835, 155, 'content_8_slides_9_img', '106'),
(6836, 155, '_content_8_slides_9_img', 'field_65e659d69a318'),
(6837, 155, 'content_8_slides_9_ttl', 'Ana'),
(6838, 155, '_content_8_slides_9_ttl', 'field_65e659e99a319'),
(6839, 155, 'content_8_slides_9_sub', ''),
(6840, 155, '_content_8_slides_9_sub', 'field_65e65a109a31a'),
(6841, 155, 'content_8_slides_9_txt', 'Conéctate contigo mismo y encuentra la armonía en esta clase de yoga Hatha Vinyasa con Ana. En este espacio, Ana te guiará a través de una meditación en movimiento que te permitirá trabajar la flexibilidad, fuerza y apertura mientras te sumerges en el momento presente y conectas con tu mente, cuerpo y alma.\r\n\r\nDiseñada para elevar tu estado de ánimo y restaurar el equilibrio en tu mente y cuerpo. Te ayudará a habitar cada postura con intención, permitiéndote explorar la profundidad de cada una mientras incorpora elementos yin de respiración, movimiento y energía.'),
(6842, 155, '_content_8_slides_9_txt', 'field_65e65a1d9a31b'),
(6843, 155, 'content_8_slides_10_img', '110'),
(6844, 155, '_content_8_slides_10_img', 'field_65e659d69a318'),
(6845, 155, 'content_8_slides_10_ttl', 'Eugenia'),
(6846, 155, '_content_8_slides_10_ttl', 'field_65e659e99a319'),
(6847, 155, 'content_8_slides_10_sub', ''),
(6848, 155, '_content_8_slides_10_sub', 'field_65e65a109a31a'),
(6849, 155, 'content_8_slides_10_txt', 'Fue formada bajo el programa de certificación para maestros de Pilates, más antiguo del mundo. Enteramente basado en la obra original de Jospeh Pilates.\r\n\r\nComo instructora busca fortalecer y corregir a través de la contrología. Basado en la repetición, control y precisión! Sin olvidar la respiración. Su clase classic esta enteramente basada en pilates autentico mientras que flow y burn son una combinación de ambos clásico y contemporáneo tanto en mat como en reformer. Siempre partiendo como base del pilates clásico.'),
(6850, 155, '_content_8_slides_10_txt', 'field_65e65a1d9a31b'),
(6851, 155, 'content_8_slides_11_img', '112'),
(6852, 155, '_content_8_slides_11_img', 'field_65e659d69a318'),
