(8344, 163, '_content_8_slides_7_sub', 'field_65e65a109a31a'),
(8345, 163, 'content_8_slides_7_txt', 'Alexandra began practicing at the age of 16 and at the age of 26 she traveled to India where she practiced with Saraswathi Jois and B.N.S Iyengar in the city of Mysore and with Sharath Jois in the city of Rishikesh. In 2018 she trained as a licensed yoga teacher at Nepal Yoga Home in Kathmandu.\r\n\r\nIn 2020, she came across the pilates mat method and became fascinated. In 2021 she trained as a Pilates teacher with teacher Elsa Monterd, founder of the Lumin Pilates school.'),
(8346, 163, '_content_8_slides_7_txt', 'field_65e65a1d9a31b'),
(8347, 163, 'content_8_slides_8_img', '109'),
(8348, 163, '_content_8_slides_8_img', 'field_65e659d69a318'),
(8349, 163, 'content_8_slides_8_ttl', 'Camilla Garza'),
(8350, 163, '_content_8_slides_8_ttl', 'field_65e659e99a319'),
(8351, 163, 'content_8_slides_8_sub', ''),
(8352, 163, '_content_8_slides_8_sub', 'field_65e65a109a31a'),
(8353, 163, 'content_8_slides_8_txt', 'Camilla got certified in Balance in Motion with Cristina Loyola in basic and intermediate Pilates Reformer and also in Pilates Mat. Camilla began giving private classes from her home along with her sister, Karla. She thus founded Reform Studio.'),
