(8756, 165, '_content_8_slides_0_sub', 'field_65e65a109a31a'),
(8757, 165, 'content_8_slides_0_txt', 'She firmly believes that yoga is a constant practice in which one never stops learning. They hold a 300-hour certification in Hatha Vinyasa and 100 advanced hours with Fabian Montes de Oca.'),
(8758, 165, '_content_8_slides_0_txt', 'field_65e65a1d9a31b'),
(8759, 165, 'content_8_slides_1_img', '105'),
(8760, 165, '_content_8_slides_1_img', 'field_65e659d69a318'),
