(10327, 184, 'content_8_slides_1_txt', 'Ana got certified with Middle Path Movement in Sayulita, Nayarit, as a Hatha Yoga and Vinyasa instructor. In her classes, she focuses on strengthening the body and mind through  meditation, fluid movement and conscious breathing.'),
(10328, 184, '_content_8_slides_1_txt', 'field_65e65a1d9a31b'),
(10329, 184, 'content_8_slides_2_img', '113'),
(10330, 184, '_content_8_slides_2_img', 'field_65e659d69a318'),
(10331, 184, 'content_8_slides_2_ttl', 'Karla Garza'),
(10332, 184, '_content_8_slides_2_ttl', 'field_65e659e99a319'),
(10333, 184, 'content_8_slides_2_sub', ''),
(10334, 184, '_content_8_slides_2_sub', 'field_65e65a109a31a'),
(10335, 184, 'content_8_slides_2_txt', 'Karla got certified with Cristina Loyola at Balance in Motion in basic, intermediate and advanced Pilates Reformer, as well as Pilates Mat. In 2022, Karla founded Reform Studio, offering private classes from her home.'),
(10336, 184, '_content_8_slides_2_txt', 'field_65e65a1d9a31b'),
(10337, 184, 'content_8_slides_3_img', '83'),
(10338, 184, '_content_8_slides_3_img', 'field_65e659d69a318'),
