INSERT INTO `wp_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES
(11697, 215, 'content_7_color', 'mint'),
(11698, 215, '_content_7_color', 'field_65e659939a315'),
(11699, 215, 'content_8_ttl', 'Meet the team'),
(11700, 215, '_content_8_ttl', 'field_65e659be9a316'),
(11701, 215, 'content_8_color', 'mint'),
(11702, 215, '_content_8_color', 'field_65e65f7a93338'),
(11703, 215, 'content_8_slides_0_img', '207'),
(11704, 215, '_content_8_slides_0_img', 'field_65e659d69a318'),
(11705, 215, 'content_8_slides_0_ttl', 'Inés Garza'),
(11706, 215, '_content_8_slides_0_ttl', 'field_65e659e99a319'),
(11707, 215, 'content_8_slides_0_sub', ''),
(11708, 215, '_content_8_slides_0_sub', 'field_65e65a109a31a'),
(11709, 215, 'content_8_slides_0_txt', 'She firmly believes that yoga is a constant practice in which one never stops learning. They hold a 300-hour certification in Hatha Vinyasa and 100 advanced hours with Fabian Montes de Oca.'),
(11710, 215, '_content_8_slides_0_txt', 'field_65e65a1d9a31b'),
(11711, 215, 'content_8_slides_1_img', '105'),
(11712, 215, '_content_8_slides_1_img', 'field_65e659d69a318'),
(11713, 215, 'content_8_slides_1_ttl', 'Ana Sofia Benavides'),
(11714, 215, '_content_8_slides_1_ttl', 'field_65e659e99a319'),
(11715, 215, 'content_8_slides_1_sub', ''),
(11716, 215, '_content_8_slides_1_sub', 'field_65e65a109a31a'),
(11717, 215, 'content_8_slides_1_txt', 'Ana got certified with Middle Path Movement in Sayulita, Nayarit, as a Hatha Yoga and Vinyasa instructor. In her classes, she focuses on strengthening the body and mind through  meditation, fluid movement and conscious breathing.'),
(11718, 215, '_content_8_slides_1_txt', 'field_65e65a1d9a31b'),
(11719, 215, 'content_8_slides_2_img', '203'),
(11720, 215, '_content_8_slides_2_img', 'field_65e659d69a318'),
(11721, 215, 'content_8_slides_2_ttl', 'Karla Garza'),
(11722, 215, '_content_8_slides_2_ttl', 'field_65e659e99a319'),
(11723, 215, 'content_8_slides_2_sub', ''),
(11724, 215, '_content_8_slides_2_sub', 'field_65e65a109a31a'),
(11725, 215, 'content_8_slides_2_txt', 'Karla got certified with Cristina Loyola at Balance in Motion in basic, intermediate and advanced Pilates Reformer, as well as Pilates Mat. In 2022, Karla founded Reform Studio, offering private classes from her home.'),
(11726, 215, '_content_8_slides_2_txt', 'field_65e65a1d9a31b'),
(11727, 215, 'content_8_slides_3_img', '200'),
(11728, 215, '_content_8_slides_3_img', 'field_65e659d69a318'),
(11729, 215, 'content_8_slides_3_ttl', 'Cecilia Cepeda'),
(11730, 215, '_content_8_slides_3_ttl', 'field_65e659e99a319'),
(11731, 215, 'content_8_slides_3_sub', ''),
(11732, 215, '_content_8_slides_3_sub', 'field_65e65a109a31a'),
(11733, 215, 'content_8_slides_3_txt', 'Cecilia got certified in Vinyasa sic years ago and has pursued other specialties in Anatomy and Biomechanics. Her classes are Vinyasa flow multilevel, with variations for everyone, working the body with great awareness and connecting with the mind through breathing and movement.'),
(11734, 215, '_content_8_slides_3_txt', 'field_65e65a1d9a31b'),
(11735, 215, 'content_8_slides_4_img', '204'),
(11736, 215, '_content_8_slides_4_img', 'field_65e659d69a318'),
(11737, 215, 'content_8_slides_4_ttl', 'Andrea Edde'),
(11738, 215, '_content_8_slides_4_ttl', 'field_65e659e99a319'),
(11739, 215, 'content_8_slides_4_sub', ''),
(11740, 215, '_content_8_slides_4_sub', 'field_65e65a109a31a'),
(11741, 215, 'content_8_slides_4_txt', 'With over 8 years of experience as a Yoga &amp; Pilates instructor, she creates training sessions for a variety of clients based on their fitness level, injuries and goals. Andrea teaches the Pilates repertoire in group settings using all equipment, including the reformer and mat.'),
(11742, 215, '_content_8_slides_4_txt', 'field_65e65a1d9a31b'),
(11743, 215, 'content_8_slides_5_img', '108'),
(11744, 215, '_content_8_slides_5_img', 'field_65e659d69a318'),
(11745, 215, 'content_8_slides_5_ttl', 'Belen Jiménez'),
(11746, 215, '_content_8_slides_5_ttl', 'field_65e659e99a319'),
(11747, 215, 'content_8_slides_5_sub', ''),
(11748, 215, '_content_8_slides_5_sub', 'field_65e65a109a31a'),
(11749, 215, 'content_8_slides_5_txt', 'Belen has been teaching Pilates reformer, wunda chair and mat classes for three years. She is certified by Alves Pilates in mat, reformer, chair, cadillac and by Balance in Motion in basic, intermediate and advanced reformer.'),
(11750, 215, '_content_8_slides_5_txt', 'field_65e65a1d9a31b'),
(11751, 215, 'content_8_slides_6_img', '201'),
(11752, 215, '_content_8_slides_6_img', 'field_65e659d69a318'),
(11753, 215, 'content_8_slides_6_ttl', 'Rodrigo Castillo'),
(11754, 215, '_content_8_slides_6_ttl', 'field_65e659e99a319'),
(11755, 215, 'content_8_slides_6_sub', ''),
(11756, 215, '_content_8_slides_6_sub', 'field_65e65a109a31a'),
(11757, 215, 'content_8_slides_6_txt', 'In 2010, Rodrigo began teaching classes using the contemporary and classical Pilates method, catering to all needs and ages at the  Bosque Real clubhouse. In 2020, he started teaching group classes in Pilates Mat and Body Art techniques.'),
(11758, 215, '_content_8_slides_6_txt', 'field_65e65a1d9a31b'),
(11759, 215, 'content_8_slides_7_img', '104'),
(11760, 215, '_content_8_slides_7_img', 'field_65e659d69a318'),
(11761, 215, 'content_8_slides_7_ttl', 'Alexandra Barzana'),
(11762, 215, '_content_8_slides_7_ttl', 'field_65e659e99a319'),
(11763, 215, 'content_8_slides_7_sub', ''),
(11764, 215, '_content_8_slides_7_sub', 'field_65e65a109a31a'),
(11765, 215, 'content_8_slides_7_txt', 'In 2018, Alexandra trained as an authorized yoga teacher at Nepal Yoga Home in Kathmandu. In 2020, amidst the pandemic, she encountered the Pilates Mat method and was fascinated by it. In 2021, she trained as a Pilates teacher with Elsa Monterd, founder of the Lumin Pilates School.'),
(11766, 215, '_content_8_slides_7_txt', 'field_65e65a1d9a31b'),
(11767, 215, 'content_8_slides_8_img', '205'),
(11768, 215, '_content_8_slides_8_img', 'field_65e659d69a318'),
(11769, 215, 'content_8_slides_8_ttl', 'Camilla Garza'),
(11770, 215, '_content_8_slides_8_ttl', 'field_65e659e99a319'),
(11771, 215, 'content_8_slides_8_sub', ''),
(11772, 215, '_content_8_slides_8_sub', 'field_65e65a109a31a'),
(11773, 215, 'content_8_slides_8_txt', 'Camila obtained her certification in Balance In Motion with Cristina Loyola in basic and intermediate Pilates Reformer, as well as Pilates. Mat. Camila began giving private classes from her home alongside her sister Karla, this founding Reform Studio.'),
(11774, 215, '_content_8_slides_8_txt', 'field_65e65a1d9a31b'),
(11775, 215, 'content_8_slides_9_img', '210'),
(11776, 215, '_content_8_slides_9_img', 'field_65e659d69a318'),
(11777, 215, 'content_8_slides_9_ttl', 'Ana Mantecón'),
(11778, 215, '_content_8_slides_9_ttl', 'field_65e659e99a319'),
(11779, 215, 'content_8_slides_9_sub', ''),
(11780, 215, '_content_8_slides_9_sub', 'field_65e65a109a31a'),
(11781, 215, 'content_8_slides_9_txt', 'Connect with yourself and find harmony in this Hatha Vinyasa yoga class with Ana. in this session, Ana will guide you through a moving meditation that allows you to work on flexibility, strength and openness while immersing yourself in the present moment and connecting with your mind, body and soul.'),
(11782, 215, '_content_8_slides_9_txt', 'field_65e65a1d9a31b'),
(11783, 215, 'content_8_slides_10_img', '213'),
(11784, 215, '_content_8_slides_10_img', 'field_65e659d69a318'),
(11785, 215, 'content_8_slides_10_ttl', 'Eugenia Russek'),
(11786, 215, '_content_8_slides_10_ttl', 'field_65e659e99a319'),
(11787, 215, 'content_8_slides_10_sub', ''),
(11788, 215, '_content_8_slides_10_sub', 'field_65e65a109a31a'),
(11789, 215, 'content_8_slides_10_txt', 'Eugenia was trained under the Pilates Teacher Certification program. As an instructor, she aims to strengthen and correct through control, based on repetition, control, and precision. Her classic class is based on authentic Pilates, while flow and burn are a combination of both classic and contemporary, both in Mat and Reformer.'),
(11790, 215, '_content_8_slides_10_txt', 'field_65e65a1d9a31b'),
(11791, 215, 'content_8_slides_11_img', '206'),
(11792, 215, '_content_8_slides_11_img', 'field_65e659d69a318'),
(11793, 215, 'content_8_slides_11_ttl', 'Irasema Ledesma'),
(11794, 215, '_content_8_slides_11_ttl', 'field_65e659e99a319'),
(11795, 215, 'content_8_slides_11_sub', ''),
(11796, 215, '_content_8_slides_11_sub', 'field_65e65a109a31a'),
(11797, 215, 'content_8_slides_11_txt', 'Irasema\'s experience includes international certifications in a wide range of disciplines. Currently, she works as a specialized coach in Pilates Reformer, Mat and in personalized training, integrating functional movements with Pilates Mat and Reformer.'),
