(13146, 224, 'cover_txt', 'Welcome to Reform Studio.\r\nReform your <a href=\"https://reformstudio.com.mx/wp-content/uploads/2024/05/Reform-Hero-Hover_Body.jpg\">body</a>. Reform your <a href=\"https://reformstudio.com.mx/wp-content/uploads/2024/05/Reform-Hero-Hover_Mind.jpg\">mind</a>.'),
(13147, 224, '_cover_txt', 'field_65f499ada7ea2'),
(13148, 224, 'content_6_ttl', 'Book Yoga'),
(13149, 224, '_content_6_ttl', 'field_65e655a69a30d'),
(13150, 224, 'content_6_color', 'white'),
(13151, 224, '_content_6_color', 'field_65e656c59a314'),
(13152, 224, 'content_6_items_0_txt', 'Use resistance, stretching and breathing exercises to reshape your body and mind.\r\n\r\n<a href=\"https://reformstudio.com.mx/rsvp\">BOOK YOUR SESSION</a>'),
(13153, 224, '_content_6_items_0_txt', 'field_65e6565c9a311'),
