(13161, 224, '_content_7_img', 'field_65e652be9a305'),
(13162, 224, 'content_7_txt', '<strong>The Reform Team</strong>'),
(13163, 224, '_content_7_txt', 'field_65e6529f9a304'),
(13164, 224, 'content_7_orden', 'left'),
(13165, 224, '_content_7_orden', 'field_65e652cb9a306'),
